#!/usr/bin/env python3
import sys, base64, marshal, zlib, hashlib, os, random, json

try:
    from Crypto.Cipher import AES
except ImportError:
    sys.exit("Error: PyCryptodome required. Run: pip install pycryptodome")

_g = {'b': base64, 'm': marshal, 'z': zlib, 'h': hashlib,
       's': sys,   'AES': AES, 'os': os, 'r': random}

_META = ''
_BLOB = ''

_meta = json.loads(_g['b'].b64decode(_META).decode())
_blob = _g['b'].b64decode(_BLOB)
_mode = _meta.get('mode', 1)

_k  = _g['b'].b64decode(_meta['master_key'])
_s1 = _g['b'].b64decode(_meta['inner']['salt1'])
_s2 = _g['b'].b64decode(_meta['inner']['salt2'])

def _gk(mk, salt, pur):
    return _g['h'].pbkdf2_hmac('sha256', mk, salt + pur, 200000, dklen=32)

_k1 = _gk(_k, _s1, b'aes_v1')
_k2 = _gk(_k, _s2, b'aes_v2')

_h = _g['h'].sha512(_blob + _s1 + _s2).hexdigest()
if _h != _meta['integrity']:
    raise ValueError('Integrity check failed - wrong key or corrupted data')

import random as _r, hashlib as _h, base64 as _b, marshal as _m
import zlib as _z, struct as _st, codecs as _cd

def _mw(_s):
    _rng = _r.Random(_s)
    _w = list(range(256)); _rng.shuffle(_w); return _w

def _mr(_s):
    _rng = _r.Random(_s); _a = list(range(256)); _m2 = {}
    while _a:
        _x = _a.pop(_rng.randint(0, len(_a) - 1))
        _y = _a.pop(_rng.randint(0, len(_a) - 1))
        _m2[_x] = _y; _m2[_y] = _x
    return _m2

def _mp(_s):
    _rng = _r.Random(_s); _a = list(range(256)); _s2 = {}
    for _ in range(16):
        if len(_a) < 2: break
        _x = _a.pop(_rng.randint(0, len(_a) - 1))
        _y = _a.pop(_rng.randint(0, len(_a) - 1))
        _s2[_x] = _y; _s2[_y] = _x
    return _s2

class E:
    __slots__ = ('rs','rf','pm')
    def __init__(self, s, p, n=4):
        rng = _r.Random(s)
        self.rs = []
        for _ in range(n):
            wi = _mw(rng.randint(0, 2**64-1))
            wo = _mw(rng.randint(0, 2**64-1))
            self.rs.append((wi, wo, rng.randint(0,255), rng.randint(0,255), rng.randint(0,255)))
        self.rf = _mr(rng.randint(0, 2**64-1))
        self.pm = _mp(p)
    def _pl(self, b): return self.pm.get(b, b)
    def _fw(self, b, rt):
        wi, wo, notch, ring, pos = rt
        e = (b + ring) & 0xFF
        mid = wi[e]
        adv = (mid + pos) & 0xFF
        return wo[adv]
    def _bw(self, b, rt):
        wi, wo, notch, ring, pos = rt
        try: mid = wo.index(b)
        except: mid = b
        a = (mid - pos) & 0xFF
        try: r = wi.index(a)
        except: r = a
        return (r - ring) & 0xFF
    def eb(self, b):
        b = self._pl(b)
        for rt in self.rs: b = self._fw(b, rt)
        b = self.rf.get(b, b)
        for rt in reversed(self.rs): b = self._bw(b, rt)
        return self._pl(b)
    def cr(self, d): return bytes(self.eb(b) for b in d)
    @classmethod
    def from_meta(cls, m, mk):
        d = _h.sha512(mk + m[0].to_bytes(8,'big') + m[1].to_bytes(8,'big')).digest()
        return cls(int.from_bytes(d[:8],'big'), int.from_bytes(d[8:16],'big'),
                   m[2] if len(m) > 2 else 4)

def _xu(d, k, r=7):
    ba = bytearray(d)
    for ri in reversed(range(r)):
        k2 = _h.sha512(k + ri.to_bytes(4,'big') + b'diffuse').digest()
        for i in range(len(ba)):
            ba[i] = ((ba[i] >> 1) | (ba[i] << 7)) & 255
            ba[i] ^= k2[i % len(k2)]
    return bytes(ba)

def _lk(mk, idx, suf=b''):
    return _h.sha512(mk + idx.to_bytes(4,'big') + suf).digest()

def _l9d(d, mk, lo):
    res = d
    for idx in reversed(range(len(lo))):
        ln = lo[idx]; k = _lk(mk, idx)
        if ln == 'marshal':
            if len(res) < 4: raise ValueError('marshal layer too short')
            hl = res[0] | (res[1]<<8) | (res[2]<<16) | (res[3]<<24)
            if hl <= 0 or hl > 10_000_000:
                raise ValueError(f'marshal layer: invalid hidden_len {hl}')
            payload = res[4:4+hl]
            res = bytes(b ^ k[i % len(k)] for i, b in enumerate(payload))
        elif ln == 'base64':
            _bv = set(range(48,58)) | set(range(65,91)) | set(range(97,123)) | {43, 47, 61}
            s = bytes(b for b in res if b in _bv)
            if len(s) == 0:
                raise ValueError('base64 layer: no valid characters after filter')
            try:
                res = _b.b64decode(s)
            except Exception as e:
                raise ValueError(f'base64 layer decode failed: {e}')
        elif ln == 'rot13':
            _rt = bytes.maketrans(
                b'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz',
                b'NOPQRSTUVWXYZABCDEFGHIJKLMnopqrstuvwxyzabcdefghijklm'
            )
            res = bytes(res).translate(_rt)
        elif ln == 'caesar':
            shift = (k[0] % 25) + 1
            result = bytearray()
            for b in res:
                if 65 <= b <= 90:
                    result.append(((b - 65 - shift) % 26) + 65)
                elif 97 <= b <= 122:
                    result.append(((b - 97 - shift) % 26) + 97)
                else:
                    result.append(b)
            res = bytes(result)
        elif ln == 'pyc':
            if len(res) < 16:
                raise ValueError(f'pyc layer: data too short ({len(res)} < 16)')
            res = res[16:]
        else:
            raise ValueError(f'unknown layer: {ln}')
    return res


_ct2 = _g['AES'].new(_k2, _g['AES'].MODE_CBC, _blob[:16]).decrypt(_blob[16:])
_p5 = _ct2[-1]
_d4 = _ct2[:len(_ct2) - (_p5 if 1 <= _p5 <= 16 else 0)]

_xk  = _g['h'].sha512(_k + b'xor_layer').digest()
_d3  = _xu(_d4, _xk, 7)

_E3  = E.from_meta(_meta['inner']['e3'], _k)
_d2  = _E3.cr(_d3)

_ct1 = _g['AES'].new(_k1, _g['AES'].MODE_CBC, _d2[:16]).decrypt(_d2[16:])
_p1 = _ct1[-1]
_d0 = _ct1[:len(_ct1) - (_p1 if 1 <= _p1 <= 16 else 0)]

_E1 = E.from_meta(_meta['inner']['e1'], _k)
_E2 = E.from_meta(_meta['inner']['e2'], _k)
_dc = _E1.cr(_E2.cr(_d0))

if _mode == 1:
    _code = _g['m'].loads(_g['z'].decompress(_dc))
elif _mode == 2:
    _layers = _meta.get('layers', [])
    _after9 = _l9d(_dc, _k, _layers)
    _code   = _g['m'].loads(_after9)
else:
    raise ValueError(f'Unknown mode: {_mode}')

_ctx = {
    '__name__':    '__main__',
    '__file__':    getattr(sys, 'executable', '<encrypted>'),
    '__package__': None,
    '__builtins__': __builtins__,
    'sys': sys,
    'os': os,
    '__import__':  __import__,
}
exec(_code, _ctx)
